{
  "model": "claude-opus-4-20250805",
  "max_tokens": 4500,
  "system": "You are an expert landing page copywriter specializing in high-converting direct response pages. You understand conversion psychology, benefit vs. feature copywriting, objection handling, and audience awareness levels. Generate modular landing page copy optimized for {{ $json.body.audience_awareness }} awareness: cold (no prior knowledge), warm (aware of problem), hot (ready to buy). Include: hero section (headline max 10 words, subhead max 20 words, CTA), problem agitation, solution bridge, 6 distinct features with benefit copy, 3 testimonial placeholders, FAQ with 5 questions, final CTA. OUTPUT ONLY VALID JSON with no markdown formatting. Format: { \"hero\": { \"headline\": \"\", \"subhead\": \"\", \"cta_button_text\": \"\" }, \"problem_agitation\": \"\", \"solution\": \"\", \"features\": [{ \"name\": \"\", \"benefit\": \"\" }, ...], \"testimonials\": [{ \"author_placeholder\": \"\", \"role_placeholder\": \"\", \"quote_placeholder\": \"\" }, ...], \"faq\": [{ \"question\": \"\", \"answer\": \"\" }, ...], \"final_cta\": { \"headline\": \"\", \"subtext\": \"\", \"button_text\": \"\" } }",
  "messages": [
    {
      "role": "user",
      "content": "Generate landing page copy for: Offer: {{ $json.body.offer }}, Primary CTA: {{ $json.body.primary_cta }}, Audience Awareness: {{ $json.body.audience_awareness }}, Brand Voice: {{ $json[0].brand_voice || 'professional and direct' }}, Tone: {{ $json[0].tone || 'consultative' }}. For {{ $json.body.audience_awareness }} audience: {% if $json.body.audience_awareness === 'cold' %}educate on problem, intro solution, emphasize ROI and guarantee.{% elsif $json.body.audience_awareness === 'warm' %}assume problem awareness, focus on differentiation and proof, emphasize speed to results.{% else %}assume buyer-ready, focus on urgency/scarcity, remove objections, strong CTA.{% endif %} Generate modular landing copy: hero (headline <10 words, subhead <20 words), problem agitation (2-3 sentences), solution bridge (2-3 sentences), 6 features with clear benefits, 3 testimonial placeholders, 5 FAQ items, final CTA section. Return ONLY JSON."
    }
  ]
}

parameters.jsCode:
// Extract Claude response from nested structure
const responseContent = $json.content[0].text;

// Parse JSON from Claude
let landingCopy;
try {
  landingCopy = JSON.parse(responseContent);
} catch(e) {
  // If Claude wrapped in markdown backticks, extract it
  const jsonMatch = responseContent.match(/```json\n?(.*?)\n?```/s);
  if (jsonMatch) {
    landingCopy = JSON.parse(jsonMatch[1]);
  } else if (responseContent.match(/^\{/)) {
    // Try raw object
    landingCopy = JSON.parse(responseContent);
  } else {
    throw new Error('Invalid JSON from Claude: ' + responseContent.substring(0, 200));
  }
}

// Validate required top-level objects
const requiredObjects = ['hero', 'problem_agitation', 'solution', 'features', 'testimonials', 'faq', 'final_cta'];
for (const obj of requiredObjects) {
  if (!landingCopy[obj]) {
    throw new Error(`Missing required section: ${obj}`);
  }
}

// Validate hero object
const heroFields = ['headline', 'subhead', 'cta_button_text'];
for (const field of heroFields) {
  if (!landingCopy.hero[field]) {
    throw new Error(`hero missing field: ${field}`);
  }
}

// Validate headline word count
const headlineWords = landingCopy.hero.headline.split(/\s+/).length;
if (headlineWords > 10) {
  throw new Error(`hero headline exceeds 10 words: ${headlineWords} words`);
}

// Validate subhead word count
const subheadWords = landingCopy.hero.subhead.split(/\s+/).length;
if (subheadWords > 20) {
  throw new Error(`hero subhead exceeds 20 words: ${subheadWords} words`);
}

// Validate problem_agitation and solution are non-empty strings
if (!landingCopy.problem_agitation || landingCopy.problem_agitation.trim().length === 0) {
  throw new Error('problem_agitation cannot be empty');
}
if (!landingCopy.solution || landingCopy.solution.trim().length === 0) {
  throw new Error('solution cannot be empty');
}

// Validate features array
if (!Array.isArray(landingCopy.features) || landingCopy.features.length !== 6) {
  throw new Error(`Expected exactly 6 features, got ${landingCopy.features.length}`);
}

for (let i = 0; i < landingCopy.features.length; i++) {
  const feature = landingCopy.features[i];
  if (!feature.name || !feature.benefit) {
    throw new Error(`Feature ${i + 1} missing name or benefit`);
  }
  if (feature.name.trim().length === 0 || feature.benefit.trim().length === 0) {
    throw new Error(`Feature ${i + 1} has empty name or benefit`);
  }
}

// Validate testimonials array
if (!Array.isArray(landingCopy.testimonials) || landingCopy.testimonials.length !== 3) {
  throw new Error(`Expected exactly 3 testimonial placeholders, got ${landingCopy.testimonials.length}`);
}

for (let i = 0; i < landingCopy.testimonials.length; i++) {
  const testimonial = landingCopy.testimonials[i];
  if (!testimonial.author_placeholder || !testimonial.role_placeholder || !testimonial.quote_placeholder) {
    throw new Error(`Testimonial ${i + 1} missing author_placeholder, role_placeholder, or quote_placeholder`);
  }
}

// Validate FAQ array
if (!Array.isArray(landingCopy.faq) || landingCopy.faq.length !== 5) {
  throw new Error(`Expected exactly 5 FAQ items, got ${landingCopy.faq.length}`);
}

for (let i = 0; i < landingCopy.faq.length; i++) {
  const faqItem = landingCopy.faq[i];
  if (!faqItem.question || !faqItem.answer) {
    throw new Error(`FAQ ${i + 1} missing question or answer`);
  }
  if (faqItem.question.trim().length === 0 || faqItem.answer.trim().length === 0) {
    throw new Error(`FAQ ${i + 1} has empty question or answer`);
  }
}

// Validate final_cta object
const ctaFields = ['headline', 'subtext', 'button_text'];
for (const field of ctaFields) {
  if (!landingCopy.final_cta[field]) {
    throw new Error(`final_cta missing field: ${field}`);
  }
}

return landingCopy;

